import { useState } from 'react';
import { useNavigate, Link } from 'react-router-dom';
import { supabase } from '../services/supabaseClient';
import { useTheme } from '../contexts/ThemeContext';

export default function Navbar({ user, setUser }) {
  const navigate = useNavigate();
  const [showDropdown, setShowDropdown] = useState(false);
  const { theme, toggleTheme } = useTheme();

  const handleLogout = async () => {
    await supabase.auth.signOut();
    setUser(null);
    setShowDropdown(false);
  };

  const toggleDropdown = () => {
    setShowDropdown(!showDropdown);
  };

  const initials = user?.email ? user.email.charAt(0).toUpperCase() : '?';

  return (
    <div className="w-full glass p-4 md:px-10 flex items-center justify-between fixed top-0 z-50">
      {/* LOGO */}
      <h1 className="text-xl font-bold cursor-pointer hover:scale-105 transition-transform duration-300" onClick={() => navigate('/')}>
        Research<span className="bg-gradient-to-r from-primary to-secondary bg-clip-text text-transparent font-bold">Mate</span>
      </h1>

      {/* MENU */}
      <div className="hidden md:flex gap-8 text-textSecondary font-medium">
        <Link to="/" className="relative pb-1 hover:text-textPrimary transition-colors duration-300 group">
          <span className="text-primary font-semibold border-b-2 border-primary pb-1">Home</span>
          <span className="absolute -bottom-1 left-0 w-0 h-0.5 bg-primary transition-all duration-300 group-hover:w-full"></span>
        </Link>
        <button className="hover:text-textPrimary hover-lift transition-all duration-300">
          AI Assistant
        </button>
        <button className="hover:text-textPrimary hover-lift transition-all duration-300">
          Paper Insights
        </button>
        <button className="hover:text-textPrimary hover-lift transition-all duration-300">
          Recommendations
        </button>
        <button className="hover:text-textPrimary hover-lift transition-all duration-300">
          Simplifier
        </button>
        <button className="hover:text-textPrimary hover-lift transition-all duration-300">
          Help
        </button>
      </div>

      {/* RIGHT SIDE */}
      <div className="flex items-center gap-4">
        {/* Theme Icon */}
        <button 
          className="text-textSecondary hover:text-textPrimary text-xl hover:rotate-180 transition-all duration-300 hover-lift glass p-2 rounded-2xl hover:shadow-glowSecondary" 
          onClick={toggleTheme}
          title="Toggle theme"
        >
          {theme === 'light' ? '🌙' : '☀️'}
        </button>

        {user ? (
          <div className="relative">
            <button
              onClick={toggleDropdown}
              className="w-10 h-10 bg-gradient-to-br from-primary to-secondary text-white rounded-full flex items-center justify-center text-sm font-bold hover:scale-110 hover:shadow-glow transition-all duration-300 shadow-glow"
              title="User menu"
            >
              {initials}
            </button>
            {showDropdown && (
              <div className="absolute right-0 mt-2 glass-card py-2 px-3 rounded-3xl shadow-glow z-50 animate-fade-in-up w-64">
                <Link
                  to="/profile"
                  className="block px-4 py-3 text-sm text-textPrimary hover:bg-white/10 hover-lift rounded-2xl mx-1 transition-all duration-200 hover:text-primary"
                  onClick={() => setShowDropdown(false)}
                >
                  Profile
                </Link>
                <button
                  onClick={handleLogout}
                  className="w-full text-left px-4 py-3 text-sm text-red-300 hover:bg-red-500/20 hover-lift rounded-2xl mx-1 transition-all duration-200"
                >
                  Sign Out
                </button>
              </div>
            )}
          </div>
        ) : (
          <button
            onClick={() => navigate("/auth")}
            className="glass px-6 py-3 rounded-3xl text-textPrimary font-semibold backdrop-blur-xl shadow-glow hover:shadow-glow hover:scale-105 transition-all duration-300 btn-secondary hover-lift"
          >
            Sign In
          </button>
        )}
      </div>
    </div>
  );
}
